var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_B","text":{"KOREA":"올레! 용병 형씨 장비가 아주 휘황찬란한데!","JPN":"オーレ！　傭兵さん、その装備すげえ豪華だな！","ENG":"Olleh! Your gear looks great, mercenary!","TWN":"Ole！傭兵大哥的裝備好像很厲害喔！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"으허억!","JPN":"うわっ！？","ENG":"Eeek!","TWN":"唔唔！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_A","text":{"KOREA":"저것 좀 봐. 머리에도 팔에도 재밌는 걸 주렁주렁 달고 있어.","JPN":"見ろよあれ。頭にも腕にも面白いのをぶら下げてるぜ。","ENG":"Look, he has a lot of interesting stuff on his head and arms.","TWN":"你看，不只是頭，手臂上也有掛那些有趣的東西。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_B","text":{"KOREA":"몇 등분으로 나누지? 6등분? 딱 6등분만 하면 되나?","JPN":"何等分にする？　6等分？　ちょうど6等分にすればいいかな？","ENG":"How shall we carve him up? Into six pieces? Would six be okay?","TWN":"要把他分成幾等分？6等分？6等分應該差不多吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_A","text":{"KOREA":"그러면 여섯 명밖에 못 나눠 가지잖아. 순서 정해서 원하는 만큼 썰자.","JPN":"それじゃ6人分にしかならないだろ？　順番決めて、好きなだけ切ろうぜ。","ENG":"No, then only six people will have him. Let’s just take turns and take as much as each person wants.","TWN":"那不就只有六個人可以分到？還是決定好順序，各自砍下想要的部位吧！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_B","text":{"KOREA":"우오오! 너 천재냐?!","JPN":"うおお！　お前、天才か！？","ENG":"Wow, you’re a genius!","TWN":"哇賽！你是天才嗎？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"해적 주제에 솔로몬 왕 같은 소릴 하는군! 이거나 가져가시지!","JPN":"海賊のくせにソロモン王のようなことを言いやがる！　これでも食らっとけ！","ENG":"A pirate that talks like Solomon? Take this!","TWN":"現在是在演所羅門王的寶藏嗎？這給你們啦！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_A","text":{"KOREA":"으음? 뭐야? 다리가 갑자기 뻣뻣해졌는데?","JPN":"うん？　なんだ？　いきなり足が固まったぞ？","ENG":"Huh? What’s going on? My legs are stiff.","TWN":"嗯？怎麼會這樣？我的腳突然動不了？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_ELECTRIC_03"},{"id":"L20_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_B","text":{"KOREA":"내 팔도 그래!","JPN":"俺の腕もだ！","ENG":"So are my arms!","TWN":"我的手臂也是！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"남자의 친구, EMP 수류탄이다. 내 비장의 무기지.","JPN":"紳士のお友達。EMP手榴弾さ。俺の切り札だ。","ENG":"That was the gentleman's friend; the EMP grenade. My ace in the hole.","TWN":"這是男人的好朋友 EMP手榴彈，是我的秘密武器！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"한동안은 꼼짝 못할 테니까 거기서 얌전히 쉬고 있으라고.","JPN":"しばらく身動きは取れないだろうから、そこで大人しく休んでろ。","ENG":"You won’t be moving for a while. So relax.","TWN":"你們會無法動彈一段時間，就乖乖在這裡休息一下吧！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_C","text":{"KOREA":"어허. 갈 때 가더라도 줄 건 줘야지.","JPN":"おっと、行く前に渡すもんがあるだろ？","ENG":"Hey, you still have something we want.","TWN":"等等，要走可以，但東西還是要留下來！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GLITCH_SCAVENGER_NULL_D","face":"UNIT_IDLE"},"C":{"char_id":"GLITCH_SCAVENGER_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_E","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"젠장, 어디서 이렇게 끝도 없이 기어 나오는 거야!?","JPN":"くそっ、どこからこんなに湧いてくるんだ！？","ENG":"Darn it, is there no end to this?","TWN":"該死！你又是從哪冒出來的？有完沒完啊？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"으음……!","JPN":"うむ……！","ENG":"Ngh!","TWN":"唔……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"거 참 신기한 몸뚱인데, 친구. 조금이나마 내 번개를 견디다니 말이야.","JPN":"たいした身体じゃないか。俺の電撃に少しでも耐えられるなんてな。","ENG":"Wow, that’s a good body, my friend. It resists my lightning, though barely.","TWN":"朋友，你不錯喔，被我的閃電打到竟然能忍得住。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"칭찬 고맙군. 내 몸을 너덜너덜하게 해 놓은 주제에.","JPN":"お褒めいただき光栄だ。俺の身体、ボロボロにしやがったくせに。","ENG":"Thank you for the compliment, but it’s all messed up now.","TWN":"多謝稱讚，雖然把我打成這樣的兇手就是你。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"확실히 알파트릭스 아가씨보다는 강하군. 두목이 나서지 않으면 어렵겠어.","JPN":"確かにアルファトリックスのお嬢ちゃんよりは強い。\\nこれはボスじゃないと厳しいかもな。","ENG":"You really are stronger than the Alphatrix girl. I think we’ll need the boss here.","TWN":"看來你比阿爾法崔克斯的小姐還強，必須請老大親自出馬！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아, 그럼 지금부터 전압을 조금 더 높여 보실까?","JPN":"ほう、それじゃあ電圧をもう少し上げてみようか！","ENG":"Oh, yeah? Then let me raise the voltage a little bit.","TWN":"那我們再把電壓調高一點嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"충천 필요한 배터리가 있으면 지금 전부 꺼내 놓으라고.","JPN":"充電が必要なバッテリーがあるなら、今のうちに全部出しとけよ。","ENG":"If you have anything that needs recharging, now's the time.","TWN":"有需要充電的電池嗎？趁這個機會全都拿出來吧！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"와우, 저 금발 녀석 끝내 주는데. 피카도르 근육 돼지들이 맥을 못 추잖아.","JPN":"わお、あの金髪野郎最高だな。ピカドールの筋肉豚野郎どもが完全に参ってる。","ENG":"Hey, that blonde guy is amazing. He’s toying with those Picador muscular pigs.","TWN":"哇賽，那個金頭髮的有兩下子欸！皮卡多爾肌肉男根本招架不住嘛！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"번개와 기계라니 상성이 좋지 않아.","JPN":"電撃と機械では相性が悪いな。","ENG":"Machines are not effective against lightning.","TWN":"閃電和機器剛好相剋。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"할 수 없군. 저 발전기 녀석에게 인양용 작살을 갈겨 버려.","JPN":"仕方ない。あの発電機野郎に引き揚げ用の銛を撃ってやれ。","ENG":"Oh well, guess we have no choice. Shoot that generator guy with our salvage harpoon.","TWN":"沒辦法，只好派出魚叉來對付那個行走發電機。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"발이 묶였을 때 그대로 함포로 끝장을 낸다.","JPN":"身動きが取れなくなったらそのまま艦砲で仕留めるんだ。","ENG":"Once he's immobilized, blast him with our cannons.","TWN":"等他的腳被纏住時，就立刻用艦砲收拾他。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"에엥? 세뇨라, 그랬다간 밖에 있는 우리 친구들까지 숯덩이가 될 텐데?","JPN":"ええっ？　セニョーラ、そんなことしたら外にいるお友達まで炭になっちまうぜ？","ENG":"Huh? Señorita, it will fry our friends out there as well!","TWN":"嗯？Senora，可是這樣的話，我們在外面的那些朋友都會一起變成砲灰欸？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래서, 뭔가 문제라도 있나?","JPN":"それが？　何か問題でもあるのか？","ENG":"So? Is there a problem?","TWN":"所以呢？有什麼問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아니! 전혀 없지! 역시 세뇨라는 똑똑하다니까! 아주 좋아!","JPN":"いや！　全くない！　さすがセニョーラは賢いぜ！　素晴らしい！","ENG":"No, not at all! You’re a genius, señorita! Very good!","TWN":"沒有！當然沒問題！Senora果然聰明！超棒的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이터니움 드라이브 출력 문제없음! 당장 쏠 수 있습니다요!","JPN":"エタニウムドライブの出力、問題なし！　今すぐ発砲できますぞ！","ENG":"Eternium Drive is all charged up; we’re ready to go!","TWN":"永恆之金引擎輸出OK！可以立刻發射！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아. 지금 당장──","JPN":"よし、今すぐ──","ENG":"Okay, now shoot—","TWN":"很好，那現在就立刻──"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"큭……! 뭐야, 공격 받은 건가?!","JPN":"くっ……！　何だ、攻撃されたのか！？","ENG":"Huh? What is that? Is this an assault?","TWN":"唔……！怎麼回事？我們被攻擊了嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어머나, 세상에. 뭔지 몰라도 방금 함선의 방어막이 박살 나버렸어.","JPN":"あらま。何だかわからないけど、たった今艦船のシールドが粉々になっちまった。","ENG":"Holy crap, something just blew out the ship’s protective shield.","TWN":"我的天，不知道是什麼東西攻擊艦船，導致艦船的防護罩整個壞掉！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"방어막이? 선체는 어떻게 됐지?","JPN":"シールドが？　船体はどうなった？","ENG":"The protective shield is gone? How’s the ship?","TWN":"防護罩？那船身呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어디 보자…….","JPN":"どれどれ……","ENG":"Let’s see...","TWN":"我看看喔……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이거 아슬아슬했네. 3번이랑 4번 통로가 완전히 부서졌어.","JPN":"こりゃあギリギリだったな。3番と4番通路が完全に壊れちまったぜ。","ENG":"That was close. Corridors number three and four are completely gone.","TWN":"有點危險欸，第3和第4通道完全毀啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"3번이랑 4번이라면…… 조금만 어긋났어도 함교가 대신 박살 났겠군.","JPN":"3番と4番か……少しズレてたら、艦橋が代わりに壊れるところだったな。","ENG":"Three and four... It could have been the bridge if it was just a bit off.","TWN":"第3和第4通道嗎……只要稍微偏一點，那遭殃的很可能就是艦橋。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"내 말이! 대체 뭐가 공격한 거래?","JPN":"それな！　いったい何に攻撃されたんだ？","ENG":"Exactly! What was that about?","TWN":"就是說啊！到底是什麼東西啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이봐, 방금 그 공격은 뭐지? 나 모르게 지원 함선이라도 숨겨둔 건가?","JPN":"おい、今の攻撃は何だ？　俺に内緒で支援艦船でも隠していたのか？","ENG":"Hey, who attacked them? Did you bring a support ship without telling me?","TWN":"喂，剛剛那是怎麼回事？是瞞著我偷偷安排的支援艦船嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……함선이 아냐, 메이슨 씨. 괴물을 숨겨 뒀지.","JPN":"……艦船じゃないさ、メイソンさん。化け物を隠しておいたんだ。","ENG":"... It’s not a ship, Mr. Mason. I brought a monster.","TWN":"……那不是艦船，梅森。是怪物。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"괴물……?","JPN":"化け物……？","ENG":"A monster?","TWN":"怪物……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"마타도르가 피해를 입은 건 예상 밖이군.","JPN":"マタドールがダメージを受けたのは想定外だな。","ENG":"I didn’t expect them to attack Matador.","TWN":"沒想到鬥牛士會受損。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L23_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"함선 급 공격인 것 같은데, 대체 어디서 날아온 거지?","JPN":"艦船級の攻撃のようだが、いったいどこから飛んできたんだ？","ENG":"I think that blast was of attack ship strength. Where did it come from?","TWN":"看來是艦船等級的攻擊，不過到底是從哪發動攻擊的？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"확실하진 않아. 어쩌면 관리국의 신형 스텔스 함선일 수도 있지.","JPN":"まだわからない。もしかしたら、管理局の新型ステルス艦船かもしれない。","ENG":"I’m not sure. Maybe it’s a new stealth ship from the Administration.","TWN":"這還無法確定，也可能是管理局的新型隱形艦船。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L25_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"늦기 전에 부하들 데리고 당장 철수해. 발목 잡히지 않게 서둘러 다이브한다.","JPN":"手遅れになる前に部下を連れてすぐ撤退しろ。\\n足止めを食らう前に急いでダイブするぞ。","ENG":"Withdraw with your men before it’s too late. We’ll dive before they can catch us.","TWN":"現在立刻帶著手下們撤退，要趕緊躍入，不能被逮到。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"　　"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"알겠다. 하지만 빈손으로 갔을 때 두목이 어떻게 나올지는 생각해 두는 게 좋을 거야.","JPN":"了解。だが、手ぶらで戻った時にボスがどう出るか、考えておいたほうが良いだろう。","ENG":"Okay. But you’ll have to think of what to say to the boss.","TWN":"好，但我們空手而歸的話，你最好先想一下要怎麼跟老大交代。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"인양용 작살에 매달린 채로 돌아가다니. 완전 미친놈들이로군.","JPN":"引き揚げ用の銛にぶら下がったまま帰還するとは、完全にイカれた連中だな。","ENG":"They dove holding that harpoon. What a bunch of lunatics.","TWN":"竟然就那樣掛著魚叉走掉，果然是一群瘋子。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그나저나 숨겨뒀다는 괴물이 누구야?","JPN":"ところで、隠しておいた化け物は誰だ？","ENG":"By the way, what’s up with the monster you talked about?","TWN":"不過，你剛說的怪物是誰？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그 쪽이 괴물이라고 부를 만한 상대는 얼마 없을 텐데……?","JPN":"そっちに化け物と呼ばれるようなやつはそうそういないと思うが……？","ENG":"There aren’t many that you call a monster, are there?","TWN":"可以讓你稱為怪物的人應該不多……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"JAINA_DELTA_NULL_SILHOUETTE","text":{"KOREA":"괴물보다는……. 협력자라고 불러 주시면 좋겠어요.","JPN":"化け物というよりは……協力者と呼んでいただければ。","ENG":"I prefer a partner, rather than a monster.","TWN":"怪物不太好聽……請稱呼我為夥伴就好。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"너, 사, 살아 있었나……? 대체 어떻게?","JPN":"あんた、い、生きてたのか……？　いったいどうやって？","ENG":"You... Y-you aren’t dead? How?","TWN":"你……竟然還活著？這是怎麼回事？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"처음 뵙네요. 제이나 크로펠이라고 합니다.","JPN":"はじめまして、ジェイナ・クロペルと申します。","ENG":"Nice to meet you. I’m Jaina Kropel.","TWN":"初次見面你好，我是婕娜·克洛佩爾。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……아마도요.","JPN":"……たぶん、ですが。","ENG":"... I think.","TWN":"應該吧……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};